import hashlib
import secrets
import json

# Simulating a user database
users_db = {}

def generate_salt():
    """Generate cryptographically secure random salt"""
    return secrets.token_hex(32)

def hash_password(password, salt):
    """Hash password with salt using SHA-256 (PBKDF2 recommended in production)"""
    combined = password + salt
    return hashlib.sha256(combined.encode()).hexdigest()

def register_user(username, password):
    """FUNCTIONAL REQ: Authentication - User Registration"""
    if username in users_db:
        return {"status": "error", "message": "User already exists"}

    salt = generate_salt()
    password_hash = hash_password(password, salt)

    users_db[username] = {
        "salt": salt,
        "password_hash": password_hash,
        "role": "user"
    }
    return {"status": "success", "message": "User registered successfully"}

def authenticate_user(username, password):
    """FUNCTIONAL REQ: Authentication - Verify user identity"""
    if username not in users_db:
        return {"status": "error", "message": "User not found"}

    user = users_db[username]
    salt = user["salt"]
    stored_hash = user["password_hash"]
    input_hash = hash_password(password, salt)

    if secrets.compare_digest(stored_hash, input_hash):
        return {"status": "success", "message": "Authentication successful", "role": user["role"]}
    return {"status": "error", "message": "Invalid credentials"}

# Demonstration
print("=== Security Functional Requirement: Authentication ===")
print(register_user("alice", "SecureP@ss123"))
print(register_user("bob", "AnotherP@ss456"))
print(authenticate_user("alice", "SecureP@ss123"))
print(authenticate_user("alice", "WrongPassword"))
